// Procedural studio environment map (equirectangular). STATIC -- no time
// reference, so this TOP cooks once and caches. vUV.st spans the 0..1
// equirectangular domain: u -> azimuth, v -> elevation (0 = bottom pole,
// 1 = top pole). Output feeds the Environment Light COMP (IBL) and the PBR
// MAT env reflection. 16-bit float so bright sun + soft sky do not band.

out vec4 fragColor;

void main()
{
    // Equirectangular angles.
    float az = vUV.s * 6.2831853;          // 0..2pi around
    float el = (vUV.t - 0.5) * 3.1415926;  // -pi/2 (down) .. +pi/2 (up)

    // World direction for this texel.
    vec3 dir = vec3(cos(el) * sin(az), sin(el), cos(el) * cos(az));

    // --- Sky gradient: cool zenith -> warm-neutral horizon -> dim floor. ---
    float up = clamp(dir.y * 0.5 + 0.5, 0.0, 1.0);      // 0 floor .. 1 zenith
    vec3 zenith = vec3(0.42, 0.55, 0.78);                // cool blue top
    vec3 horizon = vec3(0.86, 0.85, 0.82);               // bright neutral band
    vec3 floorc  = vec3(0.10, 0.10, 0.12);               // dark studio floor

    // Two-segment ramp: floor->horizon below, horizon->zenith above.
    float hb = smoothstep(0.30, 0.50, up);   // floor to horizon
    float ht = smoothstep(0.50, 0.95, up);   // horizon to zenith
    vec3 sky = mix(floorc, horizon, hb);
    sky = mix(sky, zenith, ht);

    // Bright horizon glow ring (the classic studio softbox band).
    float band = exp(-pow((up - 0.50) * 7.0, 2.0));      // gaussian at horizon
    sky += band * vec3(0.35, 0.34, 0.30);

    // --- Soft key sun disc, high and to the side (a big softbox). ---
    // Fixed direction: azimuth ~ +35deg, elevation ~ +40deg.
    vec3 sunDir = normalize(vec3(0.57, 0.64, 0.51));
    float sd = max(dot(dir, sunDir), 0.0);
    float core = pow(sd, 900.0) * 6.0;                    // tight hot core
    float halo = pow(sd, 40.0)  * 1.2;                    // soft falloff
    vec3 sun = (core + halo) * vec3(1.0, 0.96, 0.88);

    // --- Cool fill rim from the opposite side for separation. ---
    vec3 fillDir = normalize(vec3(-0.6, 0.25, -0.4));
    float fd = pow(max(dot(dir, fillDir), 0.0), 8.0) * 0.35;
    vec3 fill = fd * vec3(0.55, 0.70, 0.95);

    vec3 col = sky + sun + fill;

    // Gentle filmic-ish knee so the sun core does not blow the IBL out.
    col = col / (col + vec3(0.55));
    col *= 1.55;

    fragColor = vec4(col, 1.0);
}
